import React, { useState, useMemo } from "react";
import { Card, Typography, Row, Col, Statistic, DatePicker, Button, Space, Breadcrumb, theme, Select } from "antd";
import { BarChartOutlined, HomeOutlined, DownloadOutlined, FilterOutlined } from "@ant-design/icons";
import EChart from "@/framework/components/Chart/EChart";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages } from "../../dashboard/data/mockData";
import { faker } from "@faker-js/faker";
import dayjs from "dayjs";

const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

export default function StatPeriodPage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "common"]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const option = useMemo(() => {
    const dates = Array.from({ length: 7 }, (_, i) => dayjs().subtract(6 - i, "day").format("MM-DD"));
    
    // 선택된 보관함이 없으면 전체를 대상으로 하거나 기본 샘플 표시
    const targets = selectedIds.length > 0 
      ? mockStorages.filter(s => selectedIds.includes(s.id))
      : mockStorages.slice(0, 3); // 기본 3개 노출

    return {
      tooltip: { trigger: "axis" },
      legend: { top: 0, left: "center", orient: "horizontal", data: targets.map(t => t.name) },
      grid: { top: 40, left: "3%", right: "4%", bottom: "3%", containLabel: true },
      xAxis: {
        type: "category",
        boundaryGap: false,
        data: dates,
      },
      yAxis: { type: "value", name: `${t("storageLocker:statistics.common.temp")} / ${t("storageLocker:statistics.common.humi")}` },
      series: targets.map((locker, idx) => ({
        name: locker.name,
        type: "line",
        smooth: true,
        data: dates.map(() => faker.number.int({ min: 15, max:idx % 2 === 0 ? 30 : 60 })), // 온도/습도 혼합 샘플
        areaStyle: { opacity: 0.1 },
      })),
    };
  }, [selectedIds, t]);

  const avgTemp = useMemo(() => faker.number.float({ min: 18, max: 25, precision: 0.1 }), [selectedIds]);
  const avgHumi = useMemo(() => faker.number.float({ min: 40, max: 55, precision: 0.1 }), [selectedIds]);
  const totalCmd = useMemo(() => faker.number.int({ min: 100, max: 200 }), [selectedIds]);

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24 }}>
      <Breadcrumb
        items={[
          { title: <HomeOutlined />, href: "/" },
          { title: t("storageLocker:navigation.statistics") },
          { title: t("storageLocker:navigation.statPeriod") },
        ]}
      />

      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[16, 16]} align="middle">
          <Col md={6} lg={4}>
            <Title level={4} style={{ margin: 0 }}>
              <BarChartOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
              {t("storageLocker:navigation.statPeriod")}
            </Title>
          </Col>
          <Col flex="auto">
            <Row gutter={16} justify="end">
              <Col span={8}>
                <Select 
                  mode="multiple"
                  placeholder={t("storageLocker:dashboard.selectPlaceholder")}
                  style={{ width: "100%" }}
                  maxTagCount="responsive"
                  value={selectedIds}
                  onChange={setSelectedIds}
                  options={mockStorages.map(s => ({ label: s.name, value: s.id }))}
                  allowClear
                />
              </Col>
              <Col>
                <Space>
                  <RangePicker defaultValue={[dayjs().subtract(7, "day"), dayjs()]} />
                  <Button type="primary" icon={<FilterOutlined />}>{t("common:search")}</Button>
                  <Button icon={<DownloadOutlined />}>{t("common:exportXlsx")}</Button>
                </Space>
              </Col>
            </Row>
          </Col>
        </Row>
      </Card>

      <Row gutter={24}>
        <Col span={6}>
          <Card bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
            <Statistic title={t("storageLocker:statistics.period.avgTemp")} value={avgTemp} precision={1} suffix="°C" valueStyle={{ color: "#ff4d4f" }} />
          </Card>
        </Col>
        <Col span={6}>
          <Card bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
            <Statistic title={t("storageLocker:statistics.period.avgHumi")} value={avgHumi} precision={1} suffix="%" valueStyle={{ color: "#1890ff" }} />
          </Card>
        </Col>
        <Col span={6}>
          <Card bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
            <Statistic title={t("storageLocker:statistics.period.totalCmd")} value={totalCmd} suffix="pts" />
          </Card>
        </Col>
        <Col span={6}>
          <Card bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
            <Statistic title={t("storageLocker:statistics.period.errorRate")} value={0.5} precision={2} suffix="%" valueStyle={{ color: "#cf1322" }} />
          </Card>
        </Col>
      </Row>

      <Card bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <EChart option={option} style={{ height: 400 }} />
      </Card>
    </div>
  );
}
